12	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
13	type Customer = { yearsWithMHPCO: number };
14	type QuoteStep = { op: "quote"; items: Item[] };
15	type Scenario = { customer: Customer; steps: QuoteStep[] };
