17	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
18	
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_PREMIUM = 60;
21	
22	const groupByType = (items: Item[]): Item[][] => {
23	  const groups = new Map<string, Item[]>();
24	  for (const item of items) {
25	    const group = groups.get(item.type) ?? [];
26	    group.push(item);
27	    groups.set(item.type, group);
28	  }
29	  return [...groups.values()];
30	};
31	
32	const sumOfBasePremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
34	
35	const basePremiumForGroup = (group: Item[]): number =>
36	  group.length === COMPONENT_BLOCK_SIZE
37	    ? COMPONENT_BLOCK_PREMIUM
38	    : sumOfBasePremiums(group);
39	
40	const totalBasePremium = (items: Item[]): number =>
41	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
42	
43	const CURSE_SURCHARGE_RATE = 0.5;
44	const HIGH_ENCHANTMENT_RATE = 0.3;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const FIRST_INSURANCE_RATE = 0.1;
47	const LOYALTY_DISCOUNT_RATE = 0.2;
48	const LOYALTY_YEARS_THRESHOLD = 2;
49	
50	const firstInsuranceSurcharge = (baseTotal: number, _customer: Customer): number =>
51	  baseTotal * FIRST_INSURANCE_RATE;
52	
53	const loyaltyDiscount = (baseTotal: number, customer: Customer): number =>
54	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
55	    ? -(baseTotal * LOYALTY_DISCOUNT_RATE)
56	    : 0;
57	
58	const POLICY_MODIFIERS: ((baseTotal: number, customer: Customer) => number)[] = [
59	  firstInsuranceSurcharge,
60	  loyaltyDiscount,
61	];
62	
63	const totalPolicyModifiers = (baseTotal: number, customer: Customer): number =>
64	  POLICY_MODIFIERS.reduce((sum, modifier) => sum + modifier(baseTotal, customer), 0);
65	
66	const isCursed = (item: Item): boolean => item.cursed === true;
67	const isHighlyEnchanted = (item: Item): boolean =>
68	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
69	
70	const ITEM_SURCHARGES: { applies: (item: Item) => boolean; rate: number }[] = [
71	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
72	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
73	];
74	
75	const itemSurchargesFor = (item: Item): number => {
76	  const base = basePremiumFor(item);
77	  return ITEM_SURCHARGES.reduce(
78	    (sum, { applies, rate }) => sum + (applies(item) ? base * rate : 0),
79	    0,
80	  );
81	};
82	
83	const totalItemSurcharges = (items: Item[]): number =>
84	  items.reduce((sum, item) => sum + itemSurchargesFor(item), 0);
85	
86	const premiumFor = (items: Item[], customer: Customer): number => {
87	  const baseTotal = totalBasePremium(items);
88	  return Math.ceil(
89	    baseTotal +
90	      totalItemSurcharges(items) +
91	      totalPolicyModifiers(baseTotal, customer) +
92	      PROCESSING_FEE,
93	  );
94	};
95	
96	const resultFor = (step: QuoteStep, customer: Customer) => ({
97	  premium: premiumFor(step.items, customer),
98	});
99	
100	export const runScenario = (input: unknown): unknown => {
101	  const scenario = input as Scenario;
102	  return { results: scenario.steps.map((step) => resultFor(step, scenario.customer)) };
103	};
